export const quizData = [
  {id:1, question:"What is the short title of Republic Act No. 9292?",options:["Electronics and Communications Engineering Act","Electronics Engineering Law of 2004","Professional Electronics Regulation Act","Philippine Electronics and Technology Law"],correctIndex:1,explanation:"RA 9292 shall be known as the <strong>Electronics Engineering Law of 2004</strong> as stated in Section 1."},
  {id:2, question:"What does the State aim to develop under RA 9292's Statement of Policy?",options:["Only licensed engineers","Competent, virtuous, productive and well-rounded PECE, ECE, and ECT professionals","Government-employed electronics engineers only","Engineers who passed international certifications"],correctIndex:1,explanation:"Section 2 states the goal is to develop <strong>competent, virtuous, productive and well-rounded</strong> professionals with world-class and globally competitive standards."},
  {id:3, question:"What is 'Electronics' as defined in RA 9292?",options:["The study of electrical circuits only","Science dealing with devices involving flow of electrons or other carriers of electric charge in various media","The application of computers in industry","The design of communication systems only"],correctIndex:1,explanation:"Section 3(a) defines Electronics as the <strong>science dealing with development and application of devices involving the flow of electrons or other carriers of electric charge</strong> in vacuum, gaseous media, plasma, semiconductors, solid-state and similar devices."},
  {id:4, question:"What letters does a Professional Electronics Engineer affix to their name?",options:["ECE","ECT","PECE","PEE"],correctIndex:2,explanation:"Section 3(b) states a Professional Electronics Engineer is entitled to affix the letters <strong>PECE</strong> to their name."},
  {id:5, question:"What letters does an Electronics Engineer affix to their name?",options:["PECE","ECT","ECE","EE"],correctIndex:2,explanation:"Section 3(c) states an Electronics Engineer is entitled to affix the letters <strong>ECE</strong> to their name."},
  {id:6, question:"What letters does an Electronics Technician affix to their name?",options:["ET","ECE","PECE","ECT"],correctIndex:3,explanation:"Section 3(d) states an Electronics Technician is entitled to affix the letters <strong>ECT</strong> to their name."},
  {id:7, question:"What is 'Information and Communications Technology' (ICT) as defined in RA 9292?",options:["Only the internet and social media","Acquisition, production, transformation, storage and transmission of data/information by electronic means in vocal, pictorial, textual or numeric forms","Satellite communication systems only","Broadcasting and cable television only"],correctIndex:1,explanation:"Section 3(g) defines ICT as the <strong>acquisition, production, transformation, storage and transmission/reception of data and information by electronic means</strong> in forms such as vocal, pictorial, textual, numeric or the like."},
  {id:8, question:"What is 'Communications' as defined in RA 9292?",options:["Only wireless radio communication","The process of sending and/or receiving information between two or more points by radio, cable, optical waveguides or other devices","Sending emails over the internet","Broadcasting to a wide audience"],correctIndex:1,explanation:"Section 3(h) defines Communications as <strong>the process of sending and/or receiving information, data, signals and/or messages between two or more points</strong> by radio, cable, optical waveguides or other devices and wired or wireless medium."},
  {id:9, question:"What is 'Telecommunications' as defined in RA 9292?",options:["Only radio broadcasting","Any transmission, emission or reception of voice, data, text, images, sounds or control signals by wire, radio, visual/optical or other electronic means","Telephone communication only","Internet data transmission only"],correctIndex:1,explanation:"Section 3(i) defines Telecommunications as <strong>any transmission, emission or reception of voice, data, electronic messages, text, images, sounds, or control signals</strong> of any design/format and for any purpose by wire, radio, spectral, visual/optical/light or other electronic means."},
  {id:10, question:"What is an 'Industrial Plant' as defined in RA 9292?",options:["Only factories making electronics products","Manufacturing establishments and other business endeavors where electronic or electronically-controlled machinery/equipment are installed, used, sold, maintained, assembled, manufactured or operated","Government-owned facilities only","Power generation plants only"],correctIndex:1,explanation:"Section 3(k) defines Industrial Plant as including <strong>all manufacturing establishments and other business endeavors where electronic or electronically-controlled machinery or equipment are installed and/or used, sold, maintained, assembled, manufactured or operated</strong>."},
  {id:11, question:"Which of the following is included in the definition of 'Commercial Establishment' under RA 9292?",options:["Only office buildings","Hotels, hospitals, condominiums, supermarkets, schools, studios, stadia, watercraft and aircraft used for business","Agricultural farms","Government military installations only"],correctIndex:1,explanation:"Section 3(l) includes in Commercial Establishment: <strong>office buildings, hotels, motels, hospitals, condominiums, stores, apartments, supermarkets, schools, studios, stadia, parking areas, memorial chapels/parks, watercraft and aircraft</strong> used for business or profit."},
  {id:12, question:"What does 'Consulting Services' mean under RA 9292?",options:["General business consulting","Services requiring adequate technical expertise for advisory, feasibility studies, design, planning, construction, supervision, management and related services in electronics engineering","Marketing and sales services only","Installation and repair services only"],correctIndex:1,explanation:"Section 3(m) defines Consulting Services as <strong>services requiring adequate technical expertise, experience and professional capability</strong> for advisory and review, pre-investment or feasibility studies, design, planning, construction, supervision, management and related services in electronics engineering."},
  {id:13, question:"What are the three categories of practice covered by RA 9292?",options:["Engineer, Technician, Specialist","PECE, ECE, ECT","Senior Engineer, Junior Engineer, Technician","Licensed Engineer, Registered Engineer, Certified Technician"],correctIndex:1,explanation:"Section 4 lists the three categories as <strong>Professional Electronics Engineer (PECE), Electronics Engineer (ECE), and Electronics Technician (ECT)</strong>."},
  {id:14, question:"The scope of practice of an ECE includes which of the following fields?",options:["Only communications and telecommunications","Electronics, ICT, computers, broadcast, avionics, robotics, medical electronics, biometrics and all convergent fields","Civil and mechanical engineering works","Finance and administration only"],correctIndex:1,explanation:"Section 5(a) states the ECE scope embraces <strong>electronics, communications/telecommunications, ICT, computers, broadcast, consumer and industrial electronics, electro-optics, avionics, aerospace, medical electronics, robotics, cybernetics, biometrics and all related and convergent fields</strong>."},
  {id:15, question:"Who has the SOLE authority to provide consulting services and sign/seal technical documents?",options:["Electronics Engineer (ECE)","Electronics Technician (ECT)","Professional Electronics Engineer (PECE)","Any registered engineer"],correctIndex:2,explanation:"Section 5(b) grants the <strong>PECE the sole authority</strong> to provide consulting services and to sign and seal electronics plans, drawings, permit applications, specifications, reports and other technical documents."},
  {id:16, question:"What type of work does the Electronics Technician (ECT) scope cover?",options:["Full engineering design and consulting","Non-engineering work such as installation, construction, operation, tests, repair, maintenance, manufacture, sales and marketing of electronic components","Only repair and maintenance","Teaching engineering subjects at college level only"],correctIndex:1,explanation:"Section 5(c) states the ECT scope embraces <strong>non-engineering work</strong> relating to installation, construction, operation, control, tests and measurements, diagnosis, repair and maintenance, manufacture and production, and sales and marketing."},
  {id:17, question:"Under whose administrative control and supervision does the Board of Electronics Engineering operate?",options:["Department of Science and Technology (DOST)","Commission on Higher Education (CHED)","Professional Regulation Commission (PRC)","Technical Education and Skills Development Authority (TESDA)"],correctIndex:2,explanation:"Section 6 states the Board operates under the administrative control and supervision of the <strong>Professional Regulation Commission (PRC)</strong>."},
  {id:18, question:"How many members compose the Board of Electronics Engineering?",options:["2","3","5","7"],correctIndex:1,explanation:"Section 6 states the Board is composed of a <strong>chairman and two (2) members</strong>, totaling three (3) persons."},
  {id:19, question:"Who appoints the Chairman and members of the Board?",options:["PRC Commissioner","Secretary of DOST","President of the Philippines","Senate President"],correctIndex:2,explanation:"Section 6 states Board members shall be appointed by the <strong>President of the Philippines</strong> from the recommendees chosen by the Commission."},
  {id:20, question:"How many nominees per position does the APO submit for Board membership selection?",options:["3","4","5","6"],correctIndex:2,explanation:"Section 6 states the Commission chooses from <strong>five (5) nominees</strong> for each position submitted by the accredited professional organization."},
  {id:21, question:"How many recommendees per position does the Commission select for the President to choose from?",options:["2","3","4","5"],correctIndex:1,explanation:"Section 6 states the President appoints from <strong>three (3) recommendees per position</strong> chosen and ranked by the Commission."},
  {id:22, question:"Which of the following is a power of the Board under Section 7?",options:["Granting college degrees in electronics","Issuing, suspending or revoking Certificates of Registration and Professional ID Cards","Setting tuition fees for electronics courses","Appointing government officials in DOST"],correctIndex:1,explanation:"Section 7(d) grants the Board the power to <strong>issue, suspend or revoke Certificates of Registration and Professional Identification Cards</strong> of PECE, ECE, or ECT."},
  {id:23, question:"What program must the Board adopt for conducting licensure examinations?",options:["Manual paper-based examination program","Full computerization of the licensure examination","Oral examination program","Online open-book examination program"],correctIndex:1,explanation:"Section 7(h) requires the Board to <strong>adopt a program for the full computerization of the licensure examination</strong>."},
  {id:24, question:"The Board, in coordination with which agencies, shall review curricula for electronics engineering?",options:["DOST and DTI","CHED and TESDA","DepEd and CHED","TESDA and DOLE"],correctIndex:1,explanation:"Section 7(j) states the Board shall coordinate with <strong>CHED and TESDA</strong>, and consult with other government entities and the APO, in reviewing and defining curricula for electronics engineering."},
  {id:25, question:"Within how many years after effectivity must the Board review and define curricula for ECE/ECT programs?",options:["1 year","2 years","3 years","5 years"],correctIndex:2,explanation:"Section 7(j) provides that within <strong>three (3) years</strong> after effectivity, the Board shall review and define/re-define curricula for electronics engineering, electronics technician and allied courses."},
  {id:26, question:"How many days does a party have to appeal a Board decision to the Commission?",options:["7 days","10 days","15 days","30 days"],correctIndex:2,explanation:"Section 7(t) states that resolutions, orders and decisions are subject to appeal within <strong>fifteen (15) days</strong> from receipt thereof with the Commission."},
  {id:27, question:"If no appeal is filed within the prescribed period, what happens to a Board decision?",options:["It is automatically reviewed by the Commission","It becomes final and immediately enforceable","It is automatically reversed","It is referred to the courts"],correctIndex:1,explanation:"Section 7(t) states that if after fifteen (15) days from receipt no appeal is taken, the Board decision shall <strong>become final and immediately enforceable</strong>."},
  {id:28, question:"A Board member must be a citizen and resident of the Philippines for at least how many consecutive years prior to appointment?",options:["3 years","5 years","7 years","10 years"],correctIndex:1,explanation:"Section 8(a) requires Board members to be a citizen and <strong>resident of the Philippines for at least five (5) consecutive years</strong> prior to appointment."},
  {id:29, question:"What certificate must a Board member hold at the time of appointment?",options:["Valid Certificate as Electronics Engineer (ECE)","Valid Certificate as Electronics Technician (ECT)","Valid Certificate as Professional Electronics Engineer (PECE)","Valid Certificate from a foreign electronics board"],correctIndex:2,explanation:"Section 8(c) requires Board members to hold a valid Certificate of Registration as a <strong>Professional Electronics Engineer (PECE)</strong>."},
  {id:30, question:"How many years of active electronics engineering practice must a Board member have prior to appointment?",options:["5 years","7 years","10 years","15 years"],correctIndex:2,explanation:"Section 8(e) requires Board members to be in active practice of electronics engineering for at least <strong>ten (10) years</strong> prior to appointment."},
  {id:31, question:"A Board member must NOT have pecuniary interest in any school offering ECE/ECT courses or where review classes are held. This restriction applies:",options:["Only after appointment","Before appointment and during term","Only during the examination period","Only if they own more than 50% of the school"],correctIndex:1,explanation:"Section 8(f) states a Board member must not have any pecuniary interest, directly or indirectly, in any school offering electronics courses, <strong>nor shall they be a faculty member or administrator thereof prior to taking their oath of office</strong>."},
  {id:32, question:"A Board member must not have been convicted of an offense involving:",options:["Traffic violations","Financial fraud only","Moral turpitude","Civil liability"],correctIndex:2,explanation:"Section 8(g) disqualifies any person who has been convicted of an offense involving <strong>moral turpitude</strong> from Board membership."},
  {id:33, question:"What is the regular term of office for a Board member?",options:["1 year","2 years","3 years","4 years"],correctIndex:2,explanation:"Section 9 provides that members of the Board shall hold office for a term of <strong>three (3) years</strong> from the date of appointment."},
  {id:34, question:"How many times may a Board member be re-appointed for another full term?",options:["No re-appointment allowed","Once","Twice","Unlimited times"],correctIndex:1,explanation:"Section 9 states members may be re-appointed <strong>once</strong> for another term."},
  {id:35, question:"A person appointed to fill a Board vacancy may be re-appointed multiple times, provided their continuous tenure does not exceed:",options:["3 years","4 years","6 years","9 years"],correctIndex:2,explanation:"Section 9 provides that an appointee filling a vacancy may be re-appointed more than once as long as their continuous tenure does not exceed <strong>six (6) years</strong>."},
  {id:36, question:"On what grounds may a Board member be removed by the President?",options:["Only for criminal conviction","Neglect of duty, incompetence, manipulation of exam results, disclosure of secret exam questions, tampering of grades, unprofessional conduct, or criminal conviction","Only for financial irregularities","At the discretion of the PRC Commissioner alone"],correctIndex:1,explanation:"Section 11 lists removal grounds as: <strong>neglect of duty, incompetence, manipulation or rigging of exam results, disclosure of secret exam questions prior to the exam, tampering of grades, unprofessional or unethical conduct, or final judgment/conviction of any criminal offense</strong>."},
  {id:37, question:"Where are all records of the Board, including exam applications and administrative cases, kept?",options:["At the Board's own office","At the Department of Science and Technology","At the Professional Regulation Commission (PRC)","At the Supreme Court"],correctIndex:2,explanation:"Section 12 states that all records of the Board shall be kept by the <strong>Professional Regulation Commission (PRC)</strong>."},
  {id:38, question:"The licensure examination for ECE and ECT is governed by which Republic Act?",options:["RA 5734","RA 7920","RA 8981","RA 1080"],correctIndex:2,explanation:"Section 13 states that examinations shall be given in accordance with the provisions of <strong>Republic Act No. 8981</strong>."},
  {id:39, question:"To qualify for the ECE licensure examination, an applicant must hold a degree of:",options:["BS Computer Science or IT","BS in Electronics and Communications Engineering or Electronics Engineering, or an equivalent engineering degree","Any 4-year college degree","BS Electrical Engineering only"],correctIndex:1,explanation:"Section 14(c) requires the applicant to hold a <strong>BS in Electronics and Communications Engineering or Electronics Engineering</strong>, or subject to Board-prescribed requirements, an equivalent and/or related engineering course with a full baccalaureate degree."},
  {id:40, question:"To qualify for the ECT licensure examination, an applicant may be a graduate of:",options:["Any college course of at least 2 years","An Associate, Technician, Trade or Vocational course in electronics of not less than two (2) years, or at least minimum third-year equivalent of BS ECE/EE","Only a BS ECE or ECE program","A 1-year vocational course in any field"],correctIndex:1,explanation:"Section 14(d) allows ECT examination applicants who are graduates of <strong>an Associate, Technician, Trade or Vocational course in electronics of not less than two (2) years</strong>, or who have completed at least the minimum third-year equivalent of a BS ECE/EE program."},
  {id:41, question:"Which subject is NOT listed as a required subject for the ECE licensure examination under Section 15?",options:["Mathematics","Applied Sciences","Project Management","Communications"],correctIndex:2,explanation:"Section 15 lists the required ECE exam subjects as <strong>Mathematics, Applied Sciences, Engineering Economics, Laws and Ethics, Electronics, Communications, Computers, and ICT</strong>. Project Management is not listed."},
  {id:42, question:"The ECT examination consists of what type of tests?",options:["Written tests only","Oral examinations only","Written and/or practical tests","Computer-based tests only"],correctIndex:2,explanation:"Section 15 states the ECT examination shall consist of <strong>written and/or practical tests</strong> covering subjects specific to the practice of Electronics Technicians."},
  {id:43, question:"Who has the authority to re-cluster, rearrange, modify, add, or exclude examination subjects?",options:["The Commission on Higher Education (CHED)","The APO","The Board, after approval by the Commission","The President of the Philippines"],correctIndex:2,explanation:"Section 15 states the <strong>Board</strong> may re-cluster, rearrange, modify, add to or exclude any subject and prescribe the number of final examinations per year <strong>after approval by the Commission</strong>."},
  {id:44, question:"When the Board modifies examination subjects, where must the resolution be officially published?",options:["Only on the PRC website","In the Official Gazette or major daily newspapers and circularized to all colleges","Only at the PRC office bulletin board","In the APO newsletter"],correctIndex:1,explanation:"Section 15 requires the Board resolution on subject changes to be <strong>officially published in the Official Gazette or major daily newspapers of general circulation and also circularized and disseminated to all colleges</strong>."},
  {id:45, question:"What is the passing rating required in each subject for the ECE or ECT licensure examination?",options:["60%","65%","70%","75%"],correctIndex:2,explanation:"Section 16 states a candidate must obtain a passing rating of <strong>seventy percent (70%)</strong> in each subject given during the examination."},
  {id:46, question:"A candidate passes the majority of subjects but gets 65% in one subject. What happens?",options:["They automatically fail the entire exam","They pass conditionally","They are allowed to take one removal examination on that subject","They must retake all subjects"],correctIndex:2,explanation:"Section 16 states a candidate who passes the majority of subjects but gets a rating <strong>below 70% but not lower than 60%</strong> in the other subject(s) shall be allowed to take <strong>one removal examination</strong> on those subjects."},
  {id:47, question:"What happens if a candidate fails the removal examination?",options:["They retake only the failed removal subject","They are given a second removal exam","They are considered to have failed the entire licensure examination","They receive a conditional license"],correctIndex:2,explanation:"Section 16 states that should the examinee fail the removal examination, they shall be considered as having <strong>failed the entire licensure examination</strong>."},
  {id:48, question:"Within how many days must examination results be released after the licensure exam?",options:["7 days","10 days","15 days","30 days"],correctIndex:2,explanation:"Section 17 requires the Board and Commission to release examination results within <strong>fifteen (15) days</strong> after the said examination."},
  {id:49, question:"What is the minimum total years of active engineering experience required for PECE registration?",options:["3 years","5 years","7 years","10 years"],correctIndex:2,explanation:"Section 18(c) requires at least <strong>seven (7) years</strong> (inclusive and/or aggregate) of active self-practice or employment, at least 2 years of which must be in responsible charge of significant engineering work."},
  {id:50, question:"Of the required years of experience for PECE registration, at least how many years must be in responsible charge of significant engineering work?",options:["1 year","2 years","3 years","5 years"],correctIndex:1,explanation:"Section 18(c) requires at least <strong>two (2) years</strong> of the required experience to be in responsible charge of significant engineering work."},
  {id:51, question:"When does the required experience period for PECE registration start to count?",options:["From the date of graduation","From the date of passing the board exam","From the date the applicant took their oath as ECE","From the date of first employment"],correctIndex:2,explanation:"Section 18(c) states the experience period counts from the <strong>date the applicant took their oath as an Electronics and Communications Engineer or Electronics Engineer</strong>."},
  {id:52, question:"ECEs registered and licensed under RA 5734 for at least 7 years upon effectivity of RA 9292 need only submit which items for PECE registration?",options:["Items (a), (b), (c), and (d) plus oral interview","Items (a), (b), and (c) only — no oral interview required","Items (a) and (b) only","Only item (c) — experience record"],correctIndex:1,explanation:"Section 18 provides that those registered under RA 5734 for at least 7 years need only submit <strong>items (a) valid ECE certificate, (b) APO membership card, and (c) certified experience record — without requiring the oral interview</strong>."},
  {id:53, question:"What does a Certificate of Registration bear to authenticate it?",options:["Only the PRC Chairman's signature","The signatures of Board Chairman and Members, stamped with the official seal of the Commission and the Board","Only the signature of the President of the Philippines","Only the Board Chairman's seal"],correctIndex:1,explanation:"Section 19 states the Certificate of Registration shall bear the <strong>signature of the Chairperson and Members of the Board, stamped with the official seal of the Commission and the Board</strong>."},
  {id:54, question:"What document serves as evidence that the holder is duly registered with the Commission?",options:["Certificate of Registration","Professional Tax Receipt","Professional Identification Card","APO Membership Card"],correctIndex:2,explanation:"Section 19 states that the <strong>Professional Identification Card</strong> shall serve as evidence that the holder thereof is duly registered with the Commission."},
  {id:55, question:"The Professional Identification Card is signed by whom?",options:["Board Chairman","Secretary of DOST","Chairperson of the Commission (PRC)","President of the APO"],correctIndex:2,explanation:"Section 19 states the Professional Identification Card shall be duly signed by the <strong>Chairperson of the Commission</strong>."},
  {id:56, question:"Within how many years after the law's effectivity may Electronics Technicians register WITHOUT examination?",options:["2 years","3 years","5 years","7 years"],correctIndex:2,explanation:"Section 20 states that within <strong>five (5) years</strong> after effectivity, the Board shall issue Certificates of Registration and Professional Identification Cards without examination to qualifying ECT applicants."},
  {id:57, question:"For ECT registration without examination, the applicant must have rendered at least how many years of active practice?",options:["3 years","5 years","7 years","10 years"],correctIndex:2,explanation:"Section 20(b) requires at least <strong>seven (7) years</strong> (inclusive or aggregate) of active self-practice and/or employment as a condition for ECT registration without examination."},
  {id:58, question:"Who must certify an ECT applicant's integrity, technical capability and good moral character for registration without examination?",options:["At least two (2) registered ECEs","At least three (3) registered PECEs","At least one (1) PECE and one (1) ECE","The APO President"],correctIndex:1,explanation:"Section 20 requires submittals to be accompanied by a certification from <strong>at least three (3) registered Professional Electronics Engineers (PECEs)</strong> vouching for the applicant's integrity, technical capability and good moral character."},
  {id:59, question:"The Board shall NOT issue a Certificate of Registration to which of the following persons?",options:["A person who failed the exam once","A person convicted of a crime involving moral turpitude","A foreign national who passed the exam","A person who previously held a revoked certificate"],correctIndex:1,explanation:"Section 21 states the Board shall not register or issue a Certificate to any person <strong>convicted of a crime involving moral turpitude</strong>, any person of immoral or dishonorable conduct, or any person of unsound mind."},
  {id:60, question:"What is required BEFORE a successful examinee can be issued a Certificate of Registration and PIC?",options:["Payment of all fees only","Submission of experience records","Taking the professional oath","Membership in the APO"],correctIndex:2,explanation:"Section 22 states that ALL successful examinees must be required to take a <strong>professional oath</strong> before any Board member or person authorized by the Commission before they can be registered and issued a Certificate and PIC."},
  {id:61, question:"Taking the professional oath is a prerequisite to doing what?",options:["Applying for the licensure exam","Practicing as a PECE, ECE, or ECT","Joining the APO","Filing for PECE registration"],correctIndex:1,explanation:"Section 22 states taking the professional oath is a prerequisite to <strong>practicing as a Professional Electronics Engineer, Electronics Engineer or Electronics Technician</strong>."},
  {id:62, question:"On what grounds may the Board revoke or suspend a Certificate of Registration?",options:["Only for criminal conviction","Unprofessional or unethical conduct, malpractice, incompetence, violation of this Act or Code of Ethics, or fraud/deceit in obtaining the certificate","Only for non-payment of fees","Only for failure to renew APO membership"],correctIndex:1,explanation:"Section 23 lists grounds for revocation/suspension as: <strong>unprofessional or unethical conduct, malpractice, incompetence, any violation of this Act, Code of Ethics or Code of Technical Standards, or fraud, deceit, or false statement</strong> in obtaining the Certificate, PIC or Special Permit."},
  {id:63, question:"After how many years from revocation may a professional apply for reinstatement of their Certificate?",options:["6 months","1 year","2 years","5 years"],correctIndex:2,explanation:"Section 24 states the Board may reinstate a revoked Certificate <strong>two (2) years</strong> after revocation, upon application and for reasons deemed proper and sufficient."},
  {id:64, question:"What is the condition a professional must meet to be eligible for Certificate reinstatement?",options:["Must have completed CPE units","Must not have illegally practiced the profession or violated this Act during the revocation period","Must secure endorsement from the APO","Must pass a special competency exam"],correctIndex:1,explanation:"Section 24 states reinstatement is subject to the condition that the professional <strong>did not commit any illegal practice of the profession or any violation of this Act, its rules, codes and policies during the time the Certificate was revoked</strong>."},
  {id:65, question:"What does the Board's roster of professionals indicate for each registrant?",options:["Only their name and address","Name, address, and status of Certificate (valid, inactive, delinquent, suspended, or revoked) and APO membership status","Only their license number","Only their employment history"],correctIndex:1,explanation:"Section 25 states the roster shall indicate the <strong>status of the Certificate of Registration, Professional Identification Card and membership in the APO</strong> — whether valid, inactive, delinquent, suspended or revoked."},
  {id:66, question:"The Board's roster of professionals must be updated how often?",options:["Every month","Every 3 years","Annually","Every 5 years"],correctIndex:2,explanation:"Section 25 states the roster shall be <strong>updated annually</strong> in cooperation with the Accredited Professional Organization."},
  {id:67, question:"Under what condition may a foreign professional be exempt from examination and registration?",options:["If they pay a higher license fee","If no qualified Filipino professional is available for the specific work, as attested by the APO","If they are employed by a multinational company","If their country is a member of ASEAN"],correctIndex:1,explanation:"Section 26(a) allows exemption when <strong>no qualified equivalent Filipino professional is available for the specific item of work to be rendered, as attested to by the Accredited Professional Organization</strong>."},
  {id:68, question:"What must a foreign professional secure BEFORE commencing work in the Philippines?",options:["A working visa from the Bureau of Immigration","A Special Permit from the Board, approved by the Commission","A notarized employment contract only","A clearance from the DOLE"],correctIndex:1,explanation:"Section 26(3) requires a foreign professional to secure a <strong>Special Permit from the Board, which shall be subject to the approval of the Commission</strong>, prior to commencing work. No working visa/permit is issued unless this Special Permit is granted first."},
  {id:69, question:"For every foreign professional with a Special Permit, how many Filipino registered counterparts must be employed?",options:["At least 1","At least 2","At least 3","At least 5"],correctIndex:1,explanation:"Section 26(5) requires that <strong>at least two (2) corresponding Filipino professionals</strong> who are registered under this Act must be employed as counterparts for at least the same duration as the foreigner's tenure."},
  {id:70, question:"What is the initial validity period of a Special Permit for foreign professionals?",options:["1 month","3 months","6 months","1 year"],correctIndex:2,explanation:"Section 26(6) states the Special Permit is valid for a period of <strong>not more than six (6) months</strong> and renewable every six (6) months subject to Board discretion and Commission approval."},
  {id:71, question:"When does a Special Permit cease to be valid?",options:["After 1 year regardless of circumstances","If the foreigner terminates employment in the project and engages in another occupation requiring registration under this Act","After the project is completed only","When the foreigner returns to their home country"],correctIndex:1,explanation:"Section 26(6) states the Special Permit <strong>shall cease to be valid if the foreigner terminates employment in the work or project for which the permit was originally granted and thereafter engages in an occupation requiring another Special Permit or registration under this Act</strong>."},
  {id:72, question:"Under Section 27, who is prohibited from using the title 'Electronics Engineer'?",options:["Only foreign nationals","Any person without a valid Certificate of Registration and valid Professional Identification Card","Only those who failed the board exam","Those who have not renewed their APO membership"],correctIndex:1,explanation:"Section 27 prohibits <strong>any person without a valid Certificate of Registration and a valid Professional Identification Card</strong> from using the title 'Professional Electronics Engineer,' 'Electronics Engineer,' or 'Electronics Technician.'"},
  {id:73, question:"Can a corporation be registered and licensed to practice electronics engineering?",options:["Yes, if all its engineers are registered","Yes, if it registers with the PRC","No, practice is a personal professional service based on individual qualifications","Yes, if incorporated with the SEC"],correctIndex:2,explanation:"Section 28 states that <strong>no firm, company, partnership, association or corporation may be registered or licensed as such for the practice of electronics engineering</strong>, as it is a personal professional service."},
  {id:74, question:"May registered PECEs, ECEs, or ECTs form a partnership or corporation?",options:["No, they must practice individually only","Yes, they may form a partnership or corporation with each other or allied professionals, but each member remains individually responsible for their own acts","Yes, but only with other engineers in the same category","Only PECEs may form partnerships, not ECEs or ECTs"],correctIndex:1,explanation:"Section 28 allows registered professionals to <strong>form a partnership or association or corporation and collectively render services</strong>, provided that <strong>individual members shall be responsible for their own respective acts</strong>."},
  {id:75, question:"What must all licensed PECEs obtain and use when signing official technical documents?",options:["A government-issued stamp","A Board-prescribed seal bearing their name, registration number and title","A notarial seal","A digital signature certificate only"],correctIndex:1,explanation:"Section 29 states all licensed PECEs shall obtain and use a <strong>seal of a design prescribed by the Board bearing the registrant's name, registration number and title</strong>."},
  {id:76, question:"On every sheet of technical documents filed with government authorities, the PECE seal must also indicate which of the following?",options:["Date of graduation and school","Current PTR number, date/place of payment, and current APO membership number","Home address and contact number","Date of original licensure only"],correctIndex:1,explanation:"Section 29 requires the seal to indicate the <strong>current Professional Tax Receipt (PTR) number, date/place of payment and current membership number in the APO</strong> when filed with government authorities or used professionally."},
  {id:77, question:"Who promulgates the Code of Ethics and Code of Technical Standards of Practice for ECE and ECT?",options:["The PRC Commission","The Board alone","The Accredited Professional Organization (APO)","The Department of Science and Technology"],correctIndex:2,explanation:"Section 30 states the Code of Ethics and Code of Technical Standards of Practice shall be promulgated by the <strong>Accredited Professional Organization (APO)</strong>."},
  {id:78, question:"Under Section 31, who must comply with Continuing Professional Education (CPE) requirements?",options:["Only PECEs","Only ECEs","Only ECTs","All registered PECEs, ECEs, and ECTs"],correctIndex:3,explanation:"Section 31 states that <strong>all registered Professional Electronics Engineers, Electronics Engineers, and Electronics Technicians</strong> shall comply with CPE rules and regulations."},
  {id:79, question:"How many integrated and accredited professional organizations may exist for PECE, ECE, and ECT professionals?",options:["As many as the professionals choose to form","Two — one for engineers, one for technicians","One (1) integrated and accredited professional organization","Three — one for each category"],correctIndex:2,explanation:"Section 32 states there shall be <strong>one (1) integrated and Accredited Professional Organization</strong> for PECE, ECE and ECT professionals in the country."},
  {id:80, question:"How must the APO be organized legally?",options:["As a stock corporation registered with the SEC","As a government agency under DOST","As a non-stock, non-profit corporation registered with the Securities and Exchange Commission","As a cooperative registered with the CDA"],correctIndex:2,explanation:"Section 32 requires the APO to be registered with the <strong>Securities and Exchange Commission as a non-stock, non-profit corporation</strong>."},
  {id:81, question:"When does a newly registered PECE, ECE, or ECT automatically become an APO member?",options:["One year after registration","Upon registration with the Commission","After paying APO membership dues","After completing CPE requirements"],correctIndex:1,explanation:"Section 32 states every PECE, ECE and ECT, <strong>upon registration with the Commission</strong>, shall ipso facto become a member of the Accredited Professional Organization."},
  {id:82, question:"Previously registered professionals who are NOT yet APO members at the time of effectivity of RA 9292 have how long to register with the APO?",options:["1 year","2 years","3 years","5 years"],correctIndex:2,explanation:"Section 32 states those not yet APO members at effectivity shall be allowed to register as APO members within <strong>three (3) years</strong> after the effectivity of this Act."},
  {id:83, question:"What is the consequence of failure to maintain good standing in the APO?",options:["Automatic revocation of Certificate","Suspension from practice","Listing as delinquent in the roster of professionals","Payment of a fine"],correctIndex:2,explanation:"Section 32 states that <strong>failure to maintain membership in good standing in the APO shall be a cause for listing of the individual as delinquent</strong> in the roster of professionals."},
  {id:84, question:"Does APO membership prevent a professional from joining other electronics associations?",options:["Yes, APO membership is exclusive","No, membership in the APO shall not be a bar to membership in other associations of the electronics engineering and electronics technician professions","Yes, unless they get special Board permission","Only ECTs may join other associations"],correctIndex:1,explanation:"Section 32 explicitly states that <strong>membership in the APO shall not be a bar to membership in other associations</strong> of the electronics engineering and electronics technician professions."},
  {id:85, question:"Under the Foreign Reciprocity provision, a foreigner may register as PECE/ECE/ECT only if their country admits Filipino citizens to practice on terms of:",options:["Partial equality subject to restrictions","Strict and absolute equality with their own citizens","Equality only in certain fields","Conditional equality based on bilateral agreements"],correctIndex:1,explanation:"Section 33 requires the foreign national's country to admit Filipino citizens to practice <strong>on terms of strict and absolute equality</strong> with the citizens of said country, including unconditional recognition of Philippine licenses and degrees."},
  {id:86, question:"Within how many years from effectivity must all government positions requiring PECE/ECE/ECT services be filled only by registered professionals?",options:["1 year","2 years","3 years","5 years"],correctIndex:2,explanation:"Section 34 states that within <strong>three (3) years</strong> from effectivity, all government positions primarily requiring PECE, ECE, or ECT services shall be filled only by registered and licensed professionals."},
  {id:87, question:"Section 34 applies to which types of government positions?",options:["Only permanent positions","Only contractual positions","Career, permanent, temporary and contractual positions in both local and national government","Only national government positions"],correctIndex:2,explanation:"Section 34 covers <strong>career, permanent, temporary or contractual</strong> positions in both <strong>local and national government</strong> that primarily require PECE, ECE, or ECT services."},
  {id:88, question:"What is the minimum fine for violating RA 9292?",options:["P10,000","P50,000","P100,000","P200,000"],correctIndex:2,explanation:"Section 35 provides a fine of <strong>not less than One hundred thousand pesos (P100,000.00)</strong> nor more than One million pesos (P1,000,000.00)."},
  {id:89, question:"What is the maximum fine for violating RA 9292?",options:["P500,000","P1,000,000","P2,000,000","P5,000,000"],correctIndex:1,explanation:"Section 35 provides a fine of not less than P100,000 nor more than <strong>One million pesos (P1,000,000.00)</strong>."},
  {id:90, question:"What is the minimum imprisonment term for violating RA 9292?",options:["1 month","3 months","6 months","1 year"],correctIndex:2,explanation:"Section 35 provides imprisonment of <strong>not less than six (6) months</strong> nor more than six (6) years."},
  {id:91, question:"What is the maximum imprisonment term for violating RA 9292?",options:["3 years","5 years","6 years","10 years"],correctIndex:2,explanation:"Section 35 provides imprisonment of not less than six months nor more than <strong>six (6) years</strong>, or both fine and imprisonment, in the discretion of the court."},
  {id:92, question:"Which of the following is a punishable act under Section 35 of RA 9292?",options:["Failing the board exam","Giving false or fraudulent statements to the Board to obtain a Certificate or PIC","Applying for PECE registration before 7 years of experience","Failing to attend CPE seminars"],correctIndex:1,explanation:"Section 35(a) punishes <strong>any person who gives false or fraudulent statements to the Board to obtain a Certificate of Registration and/or Professional Identification Card</strong>."},
  {id:93, question:"Is it punishable to use another person's Certificate of Registration as your own?",options:["Only if the other person complains","No, as long as you are qualified","Yes, and it is also punishable for the owner to allow the use of their certificate","Only if used for financial gain"],correctIndex:2,explanation:"Section 35(b) punishes <strong>any person who presents or uses another person's Certificate, PIC, APO membership card or seal as their own, AND any person who allows the use of their own Certificate, PIC, membership card or seal</strong>."},
  {id:94, question:"Under Section 35(h), what electronic activities are punishable when committed by registered professionals?",options:["Downloading pirated movies personally","Illegal wire-tapping, cloning, hacking, cracking, piracy, electronic eavesdropping, violations of privacy, or maintaining unlicensed communications systems","Using social media for personal purposes","Installing personal routers without permits"],correctIndex:1,explanation:"Section 35(h) punishes registered professionals involved in <strong>illegal wire-tapping, cloning, hacking, cracking, piracy and/or other forms of unauthorized and malicious electronic eavesdropping, use of electronic devices violating privacy/safety, or maintaining unlicensed/unregistered communications systems</strong>."},
  {id:95, question:"Under Section 35(f), when is it punishable for a PECE to sign/seal a document prepared by another PECE?",options:["It is always punishable","It is punishable unless the document clearly indicates which part was actually performed by each PECE","It is never punishable between two PECEs","Only if the other PECE objects"],correctIndex:1,explanation:"Section 35(f) punishes a PECE who signs/seals any document prepared by another PECE <strong>unless the same is prepared to clearly indicate the part of such work actually performed</strong> by the signing PECE."},
  {id:96, question:"Who may law enforcement agencies assist in enforcing RA 9292?",options:["Only the courts","The Board and/or the Commission, upon their call or request","The APO only","DOST and CHED"],correctIndex:1,explanation:"Section 36 states that law enforcement agencies shall, <strong>upon call or request of the Board and/or the Commission</strong>, render assistance in enforcing this Act."},
  {id:97, question:"Upon effectivity of RA 9292, how long does the incumbent Board of Electronics and Communications Engineering have to complete all pending work?",options:["1 month","3 months","6 months","1 year"],correctIndex:2,explanation:"Section 37 states that upon effectivity, the incumbent Board shall complete all pending/unfinished works within a <strong>six (6)-month period</strong>, after which it shall cease to exist."},
  {id:98, question:"What happens to Electronics and Communications Engineers holding a valid Certificate when RA 9292 took effect?",options:["They must retake the licensure examination under the new law","They are automatically registered and recognized as Electronics Engineers and issued a new Certificate with the SAME license number","Their licenses are suspended pending re-evaluation","They are automatically elevated to PECE status"],correctIndex:1,explanation:"Section 38 states that existing ECEs shall be <strong>automatically registered and recognized as Electronics Engineers</strong> and shall be issued a new Certificate of Registration as Electronics Engineers <strong>with the same license number</strong> as their original certificate."},
  {id:99, question:"The Implementing Rules and Regulations (IRR) of RA 9292 must be adopted in coordination with which body?",options:["DOST","CHED","TESDA","The Accredited Professional Organization (APO)"],correctIndex:3,explanation:"Section 39 states the Board, <strong>in coordination with the accredited professional organization</strong>, shall adopt and promulgate the IRR, Code of Ethics, and Code of Technical Standards."},
  {id:100, question:"When does the IRR of RA 9292 take effect after publication?",options:["Immediately upon signing","7 days after publication","15 days after publication","30 days after publication"],correctIndex:2,explanation:"Section 39 states the IRR shall be effective <strong>fifteen (15) days after publication</strong> in the Official Gazette or a newspaper of general circulation."},
  {id:101, question:"What does the Separability Clause in Section 41 provide?",options:["If any part is repealed, the entire law is void","If any provision is declared unconstitutional, the other provisions remain in effect","All provisions must be implemented simultaneously","The law cannot be partially amended"],correctIndex:1,explanation:"Section 41 states that <strong>if any provision of this Act or any portion thereof is declared unconstitutional by any competent court, the other provisions hereof shall not be affected thereby</strong>."},
  {id:102, question:"Which law did RA 9292 expressly repeal?",options:["RA 7920","RA 1080","RA 5734","RA 8981"],correctIndex:2,explanation:"Section 42 explicitly states that <strong>Republic Act No. 5734</strong>, otherwise known as the 'Electronics and Communications Engineering Act of the Philippines,' is hereby repealed."},
  {id:103, question:"When does RA 9292 itself take effect?",options:["On the date it was signed","7 days after publication","15 days after full publication in the Official Gazette or any newspaper of general circulation","30 days after signing"],correctIndex:2,explanation:"Section 43 states that RA 9292 shall take effect <strong>fifteen (15) days following its full publication</strong> in the Official Gazette or any newspaper of general circulation."},
  {id:104, question:"The funding for the implementation of RA 9292 is included in which annual document?",options:["DOST Annual Budget","PRC Special Fund","Annual General Appropriations Act","APO Annual Budget"],correctIndex:2,explanation:"Section 40 states that the funding for the implementation of this Act shall be included in the <strong>annual General Appropriations Act</strong>."},
  {id:105, question:"A PECE's seal must be stamped on which pages of technical documents filed with government authorities?",options:["Only the first page","Only the last page bearing the signature","Every sheet/page","Only pages containing drawings"],correctIndex:2,explanation:"Section 29 states that technical documents prepared by or under the supervision of a PECE shall be stamped <strong>on every sheet/page</strong> with said seal."},
  {id:106, question:"Who was the President of the Philippines who signed RA 9292 into law?",options:["Fidel V. Ramos","Joseph Ejercito Estrada","Gloria Macapagal-Arroyo","Benigno Aquino III"],correctIndex:2,explanation:"RA 9292 was approved and signed by <strong>Gloria Macapagal-Arroyo</strong>, President of the Philippines, on April 17, 2004."},
  {id:107, question:"RA 9292 was finally passed by both Houses of Congress on what date?",options:["January 15, 2004","February 2, 2004","March 10, 2004","April 17, 2004"],correctIndex:1,explanation:"The Act which is a consolidation of House Bill No. 5224 and Senate Bill No. 2683 was finally passed by the House of Representatives and the Senate on <strong>February 2, 2004</strong>."},
  {id:108, question:"The scope of ECE practice also includes which of the following administrative activities?",options:["Auditing financial records","Administration, management, supervision and regulatory aspects of electronics engineering works","Human resources management","Tax compliance for electronics firms"],correctIndex:1,explanation:"Section 5(a) explicitly includes <strong>administration, management, supervision and regulatory aspects</strong> of electronics engineering works and activities within the ECE scope of practice."},
  {id:109, question:"Teaching which types of subjects falls within the scope of practice of an ECE?",options:["Only college-level theoretical subjects","Technical and professional subjects given in the electronics engineering and electronics technician curriculum and licensure examinations","Only graduate-level courses","Any subject in any engineering program"],correctIndex:1,explanation:"Section 5(a) includes in the ECE scope: <strong>teaching and training activities which develop the ability to use electronic engineering fundamentals, including lecturing and teaching of technical and professional subjects given in the electronics engineering and electronics technician curriculum and licensure examinations</strong>."},
  {id:110, question:"What does 'Broadcasting' mean under RA 9292?",options:["One-on-one communication via radio","An undertaking to transmit audio, video, text, images or signals for reception of a broad audience in a geographical area via wired or wireless means","Satellite-only communication","Government-operated radio/TV networks only"],correctIndex:1,explanation:"Section 3(j) defines Broadcasting as <strong>an undertaking the object of which is to transmit audio, video, text, images or other signals or messages for reception of a broad audience in a geographical area via wired or wireless means</strong>."},
];
